def gen(rng, size):
    n = max(2, min(size, 100))
    perm = list(range(n))
    rng.shuffle(perm)
    rank = [0] * n
    for pos, node in enumerate(perm):
        rank[node] = pos
    grid = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j and rank[i] < rank[j]:
                grid[i][j] = 1
    return [grid]

